class EventBus {
  private handlers: Map<string, Function[]> = new Map();

  emit(event: string, data: unknown) {
    const handlers = this.handlers.get(event) || [];
    for (const handler of handlers) {
      try {
        handler(data);
      } catch (e) {
        console.log('handler error', e);
      }
    }
  }
}

