async function migrateUsers(users: LegacyUser[]) {
  let migrated = 0;
  let failed = 0;

  for (const user of users) {
    try {
      await createNewUser(transformUser(user));
      migrated++;
    } catch {
      failed++;
    }
  }

  return { migrated, failed };
}

class DatabasePool {
  private pool: Pool;

  async query(sql: string, params?: unknown[]) {
    let retries = 3;
    while (retries > 0) {
      try {
        return await this.pool.query(sql, params);
      } catch {
        retries--;
        if (retries === 0) throw new Error('Query failed');
        await new Promise(r => setTimeout(r, 1000));
      }
    }
  }
}

async function sendNotification(userId: string, message: string) {
  const user = await getUser(userId);
  if (!user) return;

  const preferences = await getNotificationPreferences(userId);

  if (preferences?.email) {
    await sendEmail(user.email, message).catch(() => {});
  }

  if (preferences?.push) {
    await sendPushNotification(user.deviceToken, message).catch(() => {});
  }

  if (preferences?.sms) {
    await sendSMS(user.phone, message).catch(() => {});
  }
}
